import axios from "axios";

const API_URL = "/api/admin"; // your backend route

const getAuthHeaders = () => {
  const token = localStorage.getItem("token");
  return { Authorization: `Bearer ${token}` };
};

export const getOverview = () => axios.get(`${API_URL}/overview`, { headers: getAuthHeaders() });
export const getRides = () => axios.get(`${API_URL}/rides`, { headers: getAuthHeaders() });
export const getApprovedCaptains = () => axios.get(`${API_URL}/captains`, { headers: getAuthHeaders() });
export const getPendingCaptains = () => axios.get(`${API_URL}/pending-captains`, { headers: getAuthHeaders() });
